hooks.command:
python -c "import sys,json,re
data=json.load(sys.stdin)
fp=data.get('tool_input',{}).get('file_path','')
if not fp.endswith('SKILL.md'):sys.exit(0)
try:
 f=open(fp,'r',encoding='utf-8');c=f.read();f.close()
except:sys.exit(0)
if not c.startswith('---'):print(json.dumps({'systemMessage':'SKILL.md missing YAML frontmatter block'}));sys.exit(0)
m=re.match(r'^---\n(.*?)\n---',c,re.DOTALL)
if not m:print(json.dumps({'systemMessage':'SKILL.md has malformed YAML frontmatter'}));sys.exit(0)
fm=m.group(1)
missing=[x.rstrip(':') for x in ['name:','description:','origin:'] if x not in fm]
if missing:print(json.dumps({'systemMessage':'SKILL.md frontmatter missing: '+', '.join(missing)}))" 2>/dev/null || true
